using System.ComponentModel;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the provided message back to the caller.")]
    public static string Echo(
        [Description("The message to echo")] string message)
    {
        return $"Echo: {message}";
    }

    [McpServerTool, Description("Returns the current UTC date and time.")]
    public static string GetCurrentTime()
    {
        return DateTime.UtcNow.ToString("o");
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Config",
        MimeType = "application/json"),
     Description("Returns the application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            MaxConnections = 100,
            Features = new[] { "tools", "resources" }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://environment",
        Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns runtime environment information.")]
    public static string GetEnvironmentInfo()
    {
        var info = new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessorCount = Environment.ProcessorCount
        };

        return JsonSerializer.Serialize(info, new JsonSerializerOptions { WriteIndented = true });
    }
}

